import pytest
from your_module import is_valid_email

def test_valid_email_simple():
    assert is_valid_email("test@example.com") is True

def test_valid_email_with_subdomain():
    assert is_valid_email("user@mail.example.org") is True

def test_valid_email_with_special_chars():
    assert is_valid_email("first.last+tag_123@example.co") is True

def test_invalid_email_missing_at_symbol():
    assert is_valid_email("invalid.email.com") is False

def test_invalid_email_missing_domain():
    assert is_valid_email("user@") is False

def test_invalid_email_missing_username():
    assert is_valid_email("@example.com") is False

def test_invalid_email_invalid_tld():
    assert is_valid_email("user@example.c") is False

def test_invalid_email_spaces():
    assert is_valid_email("user name@example.com") is False
    assert is_valid_email("user@ example.com") is False

def test_invalid_email_multiple_at_symbols():
    assert is_valid_email("user@@example.com") is False

def test_edge_case_empty_string():
    assert is_valid_email("") is False

def test_edge_case_only_whitespace():
    assert is_valid_email("   ") is False

def test_edge_case_numeric_domain_allowed():
    # Allowed because regex permits alphanumeric in domain
    assert is_valid_email("user@123domain.com") is True

def test_edge_case_unicode_characters_not_allowed():
    assert is_valid_email("usér@example.com") is False

def test_error_case_non_string_input():
    with pytest.raises(TypeError):
        is_valid_email(None)   # type: ignore
